metadata.changes:
Change 1: Replace:
  "nationality": lambda s, o: (
              f"{s} is an American"
              if clean(o) in ("United States", "USA", "U.S.", "U.S.A.")
              else f"{s} is a {clean(o)} citizen"
          ),
with:
  "nationality": lambda s, o: f"{s}'s nationality is {clean(o)}",
Change 2: Replace:
  "award": lambda s, o: f"{s} received the award {clean(o)}",
with:
  "award": lambda s, o: (
              (lambda award, org: f"{s} was awarded the {award} by the {org}")(
                  *(
                      (clean(o).split('(')[0].strip(), clean(o).split('(')[1].rstrip(')'))
                      if '(' in clean(o) and ')' in clean(o)
                      else (clean(o), None)
                  )
              )
              if '(' in clean(o) and ')' in clean(o)
              else f"{s} was awarded the {clean(o)}"
          ),
